#pragma once

#include <string>
#include <utility>
#include <vector>

#include "envoy/http/filter.h"
#include "envoy/server/filter_config.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Configuration for the custom header injection filter.
 * Holds lists of headers to inject into requests and/or responses.
 */
class FilterConfig {
public:
  FilterConfig(std::vector<std::pair<std::string, std::string>> request_headers,
               std::vector<std::pair<std::string, std::string>> response_headers)
      : request_headers_to_add_(std::move(request_headers)),
        response_headers_to_add_(std::move(response_headers)) {}

  const std::vector<std::pair<std::string, std::string>>& requestHeadersToAdd() const {
    return request_headers_to_add_;
  }

  const std::vector<std::pair<std::string, std::string>>& responseHeadersToAdd() const {
    return response_headers_to_add_;
  }

private:
  std::vector<std::pair<std::string, std::string>> request_headers_to_add_;
  std::vector<std::pair<std::string, std::string>> response_headers_to_add_;
};

using FilterConfigSharedPtr = std::shared_ptr<FilterConfig>;

/**
 * HTTP filter that injects configurable headers into requests and/or responses
 * based on the filter configuration.
 *
 * Implements both StreamDecoderFilter (request path) and StreamEncoderFilter
 * (response path) to support injection on both sides.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  explicit CustomHeaderInjectionFilter(FilterConfigSharedPtr config);

  // Http::StreamFilterBase
  void onDestroy() override {}

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
                                          bool end_stream) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override {
    decoder_callbacks_ = &callbacks;
  }

  // Http::StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers,
                                          bool end_stream) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override {
    encoder_callbacks_ = &callbacks;
  }

private:
  FilterConfigSharedPtr config_;
  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "source/common/http/headers.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(FilterConfigSharedPtr config)
    : config_(std::move(config)) {}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
  for (const auto& header : config_->requestHeadersToAdd()) {
    headers.addCopy(Http::LowerCaseString(header.first), header.second);
  }
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
  for (const auto& header : config_->responseHeadersToAdd()) {
    headers.addCopy(Http::LowerCaseString(header.first), header.second);
  }
  return Http::FilterHeadersStatus::Continue;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#pragma once

#include "envoy/registry/registry.h"

#include "source/common/protobuf/protobuf.h"
#include "source/extensions/filters/http/common/factory_base.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Config registration for the custom header injection filter.
 *
 * Uses google::protobuf::Struct as config where "request_headers" and
 * "response_headers" fields are Struct objects mapping header names to values.
 *
 * Example (YAML):
 *   request_headers:
 *     x-injected-by: my-service
 *   response_headers:
 *     x-served-by: my-service
 */
class CustomHeaderInjectionConfig : public Common::FactoryBase<ProtobufWkt::Struct> {
public:
  CustomHeaderInjectionConfig() : FactoryBase("envoy.filters.http.custom_header_injection") {}

private:
  Http::FilterFactoryCb
  createFilterFactoryFromProtoTyped(const ProtobufWkt::Struct& proto_config,
                                    const std::string& stats_prefix,
                                    Server::Configuration::FactoryContext& context) override;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/config.h"

#include "envoy/registry/registry.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

namespace {

std::vector<std::pair<std::string, std::string>>
extractHeaders(const ProtobufWkt::Struct& proto_config, const std::string& field_name) {
  std::vector<std::pair<std::string, std::string>> headers;
  const auto& fields = proto_config.fields();
  auto it = fields.find(field_name);
  if (it != fields.end() && it->second.has_struct_value()) {
    for (const auto& entry : it->second.struct_value().fields()) {
      if (entry.second.has_string_value()) {
        headers.emplace_back(entry.first, entry.second.string_value());
      }
    }
  }
  return headers;
}

} // namespace

Http::FilterFactoryCb CustomHeaderInjectionConfig::createFilterFactoryFromProtoTyped(
    const ProtobufWkt::Struct& proto_config, const std::string&,
    Server::Configuration::FactoryContext&) {
  auto request_headers = extractHeaders(proto_config, "request_headers");
  auto response_headers = extractHeaders(proto_config, "response_headers");
  auto filter_config =
      std::make_shared<FilterConfig>(std::move(request_headers), std::move(response_headers));

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
  };
}

/**
 * Static registration for the custom header injection filter. @see RegisterFactory.
 */
REGISTER_FACTORY(CustomHeaderInjectionConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include <memory>
#include <string>
#include <utility>
#include <vector>

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"
#include "test/test_common/utility.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  void setUp(std::vector<std::pair<std::string, std::string>> request_headers = {},
             std::vector<std::pair<std::string, std::string>> response_headers = {}) {
    auto config = std::make_shared<FilterConfig>(std::move(request_headers),
                                                 std::move(response_headers));
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
};

TEST_F(CustomHeaderInjectionFilterTest, InjectsRequestHeader) {
  setUp({{"x-custom-header", "custom-value"}}, {});

  Http::TestRequestHeaderMapImpl headers{
      {":method", "GET"}, {":path", "/"}, {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, true));
  EXPECT_EQ("custom-value", headers.get_("x-custom-header"));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectsResponseHeader) {
  setUp({}, {{"x-response-header", "response-value"}});

  Http::TestResponseHeaderMapImpl headers{{":status", "200"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(headers, true));
  EXPECT_EQ("response-value", headers.get_("x-response-header"));
}

TEST_F(CustomHeaderInjectionFilterTest, NoHeadersConfigured) {
  setUp({}, {});

  Http::TestRequestHeaderMapImpl req_headers{
      {":method", "GET"}, {":path", "/"}, {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(req_headers, true));

  Http::TestResponseHeaderMapImpl resp_headers{{":status", "200"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(resp_headers, true));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectsBothRequestAndResponseHeaders) {
  setUp({{"x-request", "req-val"}}, {{"x-response", "resp-val"}});

  Http::TestRequestHeaderMapImpl req_headers{
      {":method", "GET"}, {":path", "/"}, {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(req_headers, true));
  EXPECT_EQ("req-val", req_headers.get_("x-request"));

  Http::TestResponseHeaderMapImpl resp_headers{{":status", "200"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(resp_headers, true));
  EXPECT_EQ("resp-val", resp_headers.get_("x-response"));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectsMultipleRequestHeaders) {
  setUp({{"x-header-a", "value-a"}, {"x-header-b", "value-b"}}, {});

  Http::TestRequestHeaderMapImpl headers{
      {":method", "GET"}, {":path", "/"}, {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, true));
  EXPECT_EQ("value-a", headers.get_("x-header-a"));
  EXPECT_EQ("value-b", headers.get_("x-header-b"));
}

TEST_F(CustomHeaderInjectionFilterTest, PassThroughDataAndTrailers) {
  setUp({{"x-injected", "val"}}, {});

  Http::MockRequestTrailerMapImpl trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->decodeTrailers(trailers));

  Buffer::OwnedImpl data("test");
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));
}

TEST_F(CustomHeaderInjectionFilterTest, FilterConfigAccessors) {
  std::vector<std::pair<std::string, std::string>> req_hdrs{{"x-req", "val1"}};
  std::vector<std::pair<std::string, std::string>> resp_hdrs{{"x-resp", "val2"}};
  FilterConfig config(req_hdrs, resp_hdrs);

  ASSERT_EQ(1u, config.requestHeadersToAdd().size());
  EXPECT_EQ("x-req", config.requestHeadersToAdd()[0].first);
  EXPECT_EQ("val1", config.requestHeadersToAdd()[0].second);

  ASSERT_EQ(1u, config.responseHeadersToAdd().size());
  EXPECT_EQ("x-resp", config.responseHeadersToAdd()[0].first);
  EXPECT_EQ("val2", config.responseHeadersToAdd()[0].second);
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

