std::vector<std::pair<std::string, std::string>>
extractHeaders(const ProtobufWkt::Struct& proto_config, const std::string& field_name) {
  std::vector<std::pair<std::string, std::string>> headers;
  const auto& fields = proto_config.fields();
  auto it = fields.find(field_name);
  if (it != fields.end() && it->second.has_struct_value()) {
    for (const auto& entry : it->second.struct_value().fields()) {
      if (entry.second.has_string_value()) {
        headers.emplace_back(entry.first, entry.second.string_value());
      }
    }
  }
  return headers;
}

